#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long powmod(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

long long factorial(long long n) {
    long long res = 1;
    for (long long i = 1; i <= n; i++) {
        res = (res * i) % MOD;
    }
    return res;
}

long long combination(long long n, long long k) {
    long long res = factorial(n);
    res = (res * powmod(factorial(k), MOD - 2)) % MOD;
    res = (res * powmod(factorial(n - k), MOD - 2)) % MOD;
    return res;
}

int main() {
    long long N, M;
    scanf("%lld %lld", &N, &M);
    long long result = 0;
    for (long long i = 0; i <= N * M; i++) {
        result = (result + combination(N * M, i)) % MOD;
    }
    printf("%lld\n", result);
    return 0;
}

